import{f as a,g as n,J as e}from"./common-03e46d7f.js";const s='{"title":"搭建博客记录","frontmatter":{"date":"2022-06-10","title":"搭建博客记录","tags":["tool"],"describe":"使用vitepress搭建博客，通过github pages生成在线访问地址"},"headers":[{"level":2,"title":"vitepress 文档","slug":"vitepress-文档"},{"level":3,"title":"配置","slug":"配置"},{"level":3,"title":"markdown 拓展","slug":"markdown-拓展"},{"level":3,"title":"创建博客项目","slug":"创建博客项目"},{"level":3,"title":"发布到 github pages","slug":"发布到-github-pages"},{"level":3,"title":"发布到 gitlab pages","slug":"发布到-gitlab-pages"},{"level":2,"title":"Final cut pro 教程","slug":"final-cut-pro-教程"},{"level":2,"title":"视频剪辑","slug":"视频剪辑"},{"level":3,"title":"素材窗口","slug":"素材窗口"},{"level":3,"title":"时间线","slug":"时间线"},{"level":2,"title":"关键帧","slug":"关键帧"},{"level":2,"title":"视频导出","slug":"视频导出"},{"level":2,"title":"视频效果","slug":"视频效果"},{"level":2,"title":"音频效果","slug":"音频效果"},{"level":2,"title":"色彩校正","slug":"色彩校正"},{"level":2,"title":"常用快捷键","slug":"常用快捷键"}],"relativePath":"docs/tool/blog.md","lastUpdated":1703553176394.7969}';var t={};const p=[e('<p>因为是使用 vitepress 搭建博客，所以先需要了解一下<a href="https://vitejs.cn/vitepress/" target="_blank" rel="noopener noreferrer">vitepress</a></p><h2 id="vitepress-文档"><a class="header-anchor" href="#vitepress-文档" aria-hidden="true">#</a> vitepress 文档</h2><h3 id="配置"><a class="header-anchor" href="#配置" aria-hidden="true">#</a> 配置</h3><ul><li><p>文档目录下创建一个 <code>.vuepress</code> 目录，存放所有 <code>VuePress</code> 相关的文件</p></li><li><p>配置文件 <code>.vuepress/config.js</code>，导出一个 JavaScript 对象</p><div class="language-js"><pre><code>module<span class="token punctuation">.</span>exports <span class="token operator">=</span> <span class="token punctuation">{</span>\n  <span class="token literal-property property">title</span><span class="token operator">:</span> <span class="token string">&#39;Hello VitePress&#39;</span><span class="token punctuation">,</span>\n  <span class="token literal-property property">description</span><span class="token operator">:</span> <span class="token string">&#39;Just playing around.&#39;</span><span class="token punctuation">,</span>\n<span class="token punctuation">}</span>\n</code></pre></div></li></ul><h3 id="markdown-拓展"><a class="header-anchor" href="#markdown-拓展" aria-hidden="true">#</a> markdown 拓展</h3><p><a href="https://vitejs.cn/vitepress/guide/markdown.html" target="_blank" rel="noopener noreferrer">原文链接</a></p><ul><li><p>文件夹下的 <code>index.md</code> 文件都会被自动编译为 <code>index.html</code>，对应的链接将被视为 <code>/</code></p><div class="language-bash"><pre><code><span class="token builtin class-name">.</span>\n├─ index.md\n├─ foo\n│  ├─ index.md\n│  ├─ one.md\n│  └─ two.md\n└─ bar\n  ├─ index.md\n  ├─ three.md\n  └─ four.md\n</code></pre></div><p>会被编译为</p><div class="language-bash"><pre><code><span class="token punctuation">[</span>Home<span class="token punctuation">]</span><span class="token punctuation">(</span>/<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 跳转到根目录的index.md --<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>foo<span class="token punctuation">]</span><span class="token punctuation">(</span>/foo/<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 跳转到 foo 文件夹的 index.html--<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>foo heading<span class="token punctuation">]</span><span class="token punctuation">(</span>./<span class="token comment">#heading) &lt;!-- 跳转到 foo/index.html 的特定标题位置 --&gt;</span>\n<span class="token punctuation">[</span>bar - three<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/three<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 你可以忽略扩展名 --<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>bar - three<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/three.md<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 具体文件可以使用 .md 结尾（推荐）--<span class="token operator">&gt;</span>\n<span class="token punctuation">[</span>bar - four<span class="token punctuation">]</span><span class="token punctuation">(</span><span class="token punctuation">..</span>/bar/four.html<span class="token punctuation">)</span> <span class="token operator">&lt;</span><span class="token operator">!</span>-- 也可以用 .html--<span class="token operator">&gt;</span>\n</code></pre></div></li><li><p>Frontmatter</p><p>任何包含 YAML frontmatter 块的 Markdown 文件都将由 gray-matter 处理。Frontmatter 块必须位于在 Markdown 文件的顶部，必须是有效的 YAML 格式，放置在三点划线之间。例如：</p><div class="language-md"><pre><code><span class="token front-matter-block"><span class="token punctuation">---</span>\n<span class="token front-matter yaml language-yaml">title: Docs with VitePress\neditLink: true</span>\n<span class="token punctuation">---</span></span>\n</code></pre></div></li></ul><h3 id="创建博客项目"><a class="header-anchor" href="#创建博客项目" aria-hidden="true">#</a> 创建博客项目</h3><blockquote><p>可以使用<a href="https://vitejs.cn/vitepress/" target="_blank" rel="noopener noreferrer">vitepress 官方文档</a>按照步骤创建，我是直接在 github 上克隆别人已有的博客进行修改<br> 博客地址：<a href="http://jexlau.github.io/blog/" target="_blank" rel="noopener noreferrer">jexlau.github.io/blog/</a></p></blockquote><ul><li><p>克隆项目</p><div class="language-bash"><pre><code><span class="token function">git</span> clone https://github.com/JexLau/blog.git\n<span class="token builtin class-name">cd</span> blog\n\n<span class="token comment"># 安装依赖</span>\n<span class="token function">yarn</span>\n\n<span class="token comment"># 在本地启动服务器</span>\n<span class="token function">yarn</span> dev\n\n<span class="token comment"># 构建静态文件 &gt; .vitepress/dist</span>\n<span class="token function">yarn</span> build\n</code></pre></div></li><li><p>修改配置</p><ul><li><p>.vitepress 是项目页面的配置，可以根据自己的想法更改</p></li><li><p>docs 中用于存放自己的 md 文档，存放你自己的文档，注意格式如下</p><div class="language-md"><pre><code><span class="token front-matter-block"><span class="token punctuation">---</span>\n<span class="token front-matter yaml language-yaml">date: 2022-06-10\ntitle: 搭建博客记录\ntags:\n  - 博客\ndescribe: 使用vitepress搭建博客，通过github pages生成在线访问地址</span>\n<span class="token punctuation">---</span></span>\n</code></pre></div></li><li><p>more 中用于存放导航栏的标签</p></li></ul></li></ul><h3 id="发布到-github-pages"><a class="header-anchor" href="#发布到-github-pages" aria-hidden="true">#</a> 发布到 github pages</h3><ul><li><p>github 创建 blog 仓库<code>Create a new repository</code></p></li><li><p>先将本地代码推到远程仓库，便于存储及之后修改</p></li><li><p>修改 <a href="http://deploy.sh" target="_blank" rel="noopener noreferrer">deploy.sh</a> 脚本文件</p><ul><li><p>先将本地文件提交到 github master 分支</p></li><li><p>修改 <a href="http://deploy.sh" target="_blank" rel="noopener noreferrer">deploy.sh</a>，将 github 地址改为你自己的地址</p><div class="language-bash"><pre><code><span class="token comment"># 如果发布到 https://&lt;USERNAME&gt;.github.io/&lt;REPO&gt;</span>\n<span class="token function">git</span> push -f https://github.com/wang1xiang/blog.git master:gh-pages\n</code></pre></div></li><li><p>yarn deploy 发布，如果没有成功，可以按照 <a href="http://deploy.sh" target="_blank" rel="noopener noreferrer">deploy.sh</a> 的文件一步步执行，看是哪里的问题</p></li></ul></li><li><p>查看发布成功后的地址<a href="https://wang1xiang.github.io/blog/" target="_blank" rel="noopener noreferrer">https://wang1xiang.github.io/blog/</a>，如果没有刷新，强制刷新一下试试</p></li></ul><h3 id="发布到-gitlab-pages"><a class="header-anchor" href="#发布到-gitlab-pages" aria-hidden="true">#</a> 发布到 gitlab pages</h3><h2 id="final-cut-pro-教程"><a class="header-anchor" href="#final-cut-pro-教程" aria-hidden="true">#</a> Final cut pro 教程</h2><ol><li><p>资源库</p><p>fcpx 的工程文件，包含多个事件</p><p>资源库创建成功后，会自动创建一个事件，日期命名（2023-12-19），相当于一个文件夹，在访达目录中可找到</p></li><li><p>事件</p><p>事件就是文件夹，如：按日期分类，可以包含多个项目</p></li><li><p>项目</p><p>项目就是时间线上的所有内容，当前剪辑的内容 <img src="/blog/_assets/final-cut-pro-new.688e9e07.png" alt="final-cut-pro-new"></p><p>使用自定义设置，完成后 自动设置也可</p><p><img src="/blog/_assets/final-cut-pro-three.1d6149ca.png" alt="final-cut-pro-three"></p><p>左上角音效、字幕，右下角转场和效果可以运用在所有事件中</p></li><li><p>添加视频素材</p><p>拖到时间线当中</p></li></ol><p><img src="/blog/_assets/final-cut-pro-window.00632f08.png" alt="final-cut-pro-window"></p><ul><li>素材窗口</li><li>预览窗口</li><li>检查器窗口：调整片段参数</li><li>时间线窗口：剪辑、加工工作</li></ul><h2 id="视频剪辑"><a class="header-anchor" href="#视频剪辑" aria-hidden="true">#</a> 视频剪辑</h2><h3 id="素材窗口"><a class="header-anchor" href="#素材窗口" aria-hidden="true">#</a> 素材窗口</h3><p>可用于粗剪，如选择视频片段</p><ul><li><p>查看片段：j 后退、k 暂停、l 前进、ll 快进</p></li><li><p>选择片段：i 选择开头、o 选择结尾</p></li><li><p>插入片段/添加字幕</p><p>e 直接添加到片段末尾、w 插入到红线位置</p><p>q 直接添加到红线前、shift + q 添加到红线之后</p></li></ul><h3 id="时间线"><a class="header-anchor" href="#时间线" aria-hidden="true">#</a> 时间线</h3><ul><li><p>时间线大小调整 cmd+/- 调整大小 shift + z 适应大小</p></li><li><p>片段删除 delete 删除 option + cmd + delete 仅删除主时间线</p></li><li><p>速度控制</p><p>30 帧的片段，需要 60 帧的片段，才能无损的以 50%的速度慢放 cmd + r 调出速度控制器 shift + b 将片段速度切割成不同的部分进行调整</p></li></ul><p>A-roll：主时间线，Vlog 的主线内容，能够保证整个 vlog 的连续性，让观看的人明白你要干什么、你在做什么 B-roll：主时间线上方的视频：当播放到此位置时，画面会从主时间线跳转到上面的视频，能够强化 Vlog 内容</p><h2 id="关键帧"><a class="header-anchor" href="#关键帧" aria-hidden="true">#</a> 关键帧</h2><p>完成两个关键状态帧之间的过渡画面，动画如何产生：两个帧的参数不一样，就会有动画效果。</p><ul><li>模拟运动镜头，可以在关键帧处放大或缩小视频</li><li>视频慢慢放大</li><li>文本慢慢消失：不透明的关键帧，下一个关键帧设为透明</li></ul><h2 id="视频导出"><a class="header-anchor" href="#视频导出" aria-hidden="true">#</a> 视频导出</h2><p>cmd + e</p><p><img src="/blog/_assets/final-cut-pro-mind.196ce2e8.png" alt="final-cut-pro-mind"></p><p>图像纠正和畸变修复是视频编辑中常见的任务之一。在使用 Final Cut Pro 进行视频编辑时，掌握一些图像纠正和畸变修复的技巧，可以让你的视频更加专业和令人印象深刻。下面将介绍一些 Final Cut Pro 中常用的图像纠正和畸变修复技巧。</p><ol><li>手动校正 Final Cut Pro 提供了一些手动校正工具，可以帮助你调整图像的水平和垂直位置以及旋转角度。首先，在选定需要调整的视频素材后，点击“效果”选项卡，并选择“视频效果”中的“校正”。在校正的选项中，你可以通过调整滑块来实现图像的自由旋转和缩放，以及对齐图像的水平和垂直位置。</li><li>视频稳定 图像抖动是拍摄视频过程中常见的问题之一。Final Cut Pro 提供了视频稳定工具，可以帮助你稳定抖动的视频素材。选中需要修复的视频素材后，点击“效果”选项卡，并在“视频效果”中选择“稳定”。在稳定的选项中，你可以通过调整滑块来对视频进行稳定处理。</li><li>镜头畸变修复 镜头畸变是一种常见的问题，尤其是广角镜头拍摄的素材中容易出现畸变效果。Final Cut Pro 提供了镜头畸变修复工具，可以帮助你修复广角镜头拍摄的素材中的畸变效果。选择需要修复的视频素材后，点击“效果”选项卡，并在“视频效果”中选择“畸变修复”。在畸变修复的选项中，你可以通过调整滑块来修复不同类型的畸变效果。</li><li>色彩校正 在一些情况下，视频素材的色彩可能不准确，需要进行校正。Final Cut Pro 提供了多种色彩校正工具，可以帮助你调整视频素材的亮度、对比度、色相和饱和度等参数。选择需要调整的视频素材后，点击“效果”选项卡，并在“视频效果”中选择“色彩校正”。在色彩校正的选项中，你可以通过调整各个参数的滑块来实现色彩的修正。</li><li>去噪和修复 视频素材中可能存在噪点或其他干扰，Final Cut Pro 提供了去噪和修复工具，可以帮助你清除噪点和修复干扰。选中需要处理的视频素材后，点击“效果”选项卡，并在“音频效果”中选择“去噪”或“修复”。在去噪和修复的选项中，你可以通过调整滑块来降低噪点和修复干扰。</li></ol><h2 id="视频效果"><a class="header-anchor" href="#视频效果" aria-hidden="true">#</a> 视频效果</h2><ul><li><p>风格化 超级 8 毫米：复古效果 摄录机：vlog 专用的视频框</p></li><li><p>聚焦 模糊 -&gt; 聚焦（整体模糊，局部清晰效果，制造“伪景深效果”；极大提升画面的通透感，凸显画面主体）</p></li><li><p>抠像 抠像 -&gt; 抠像（从画面抠选出一部分，将其他部分从画面抹去，类似色彩被抹去） 显示选择遮罩：白色表示要留的部分，黑色表示要抹去的部分 抠像 -&gt; 亮度抠像器 将亮部或暗部从画面中抹去</p></li><li><p>遮罩 遮罩 -&gt; 绘制遮罩 被抹去的部分变成透明</p></li></ul><h2 id="音频效果"><a class="header-anchor" href="#音频效果" aria-hidden="true">#</a> 音频效果</h2><h2 id="色彩校正"><a class="header-anchor" href="#色彩校正" aria-hidden="true">#</a> 色彩校正</h2><p>也就是后期调色</p><ul><li><p>颜色</p><p>全局、阴影、中间调、曝光</p></li><li><p>饱和度</p><p>阴影、中间调、曝光</p></li><li><p>曝光</p><p>阴影、中间调、曝光</p></li></ul><h2 id="常用快捷键"><a class="header-anchor" href="#常用快捷键" aria-hidden="true">#</a> 常用快捷键</h2><p><img src="/blog/_assets/fcpx-shortcut-keys.ddc48af0.png" alt="fcpx-shortcut-keys"></p>',40)];t.render=function(e,s,t,l,o,i){return a(),n("div",null,p)};export{s as __pageData,t as default};
